#!/bin/bash
# Name: HF qwen2.5-14b-instruct-gptq-int8
# Description: Local HF snapshot via vLLM (INT8, 16.7 GB on disk)
# VRAM: 34
#
# Auto-generated by DGX Model Manager from:
# /mnt/models/qwen2.5-14b-instruct-gptq-int8
set -euo pipefail

docker rm -f vllm_node 2>/dev/null || true

exec docker run --name vllm_node --restart unless-stopped --gpus all -p 8000:8000 \
  -v "/mnt/models/qwen2.5-14b-instruct-gptq-int8:/models/qwen2.5-14b-instruct-gptq-int8:ro" \
  -e HF_HUB_OFFLINE=1 \
  -e CUDA_DEVICE_MAX_CONNECTIONS=8 \
  vllm/vllm-openai:v0.20.0 \
  --model "/models/qwen2.5-14b-instruct-gptq-int8" \
  --served-model-name "qwen2.5-14b-instruct-gptq-int8" "qwen2.5-14b-instruct-gptq-int8" vllm-active \
  --host 0.0.0.0 --port 8000 \
  --trust-remote-code --dtype auto \
  --gpu-memory-utilization 0.75 \
  --max-model-len 32768 --max-num-seqs 2 \
  --kv-cache-dtype fp8 --enable-chunked-prefill \
  --generation-config vllm
